  else return (2 * f1(n-1) + 3 * f1(n-2));
}

int f2(int n) {
  int X[N], Y[N], Z[N];
  X[0] = Y[0] = Z[0] = 0;
  X[1] = 1; Y[1] = 2; Z[1] = 3;
  for (int i = 2; i <= n; i++) {
    X[i] = Y[i-1] + Z[i-2];
    Y[i] = 2 * X[i];
    Z[i] = 3 * X[i];
  }
  return X[n];
}

