Consider the following proposal to the 'readers and writers problem.'

Shared variables and semaphores:
  aw, ar, rw, rr : integer;
  mutex, reading, writing : semaphore;

Initial values: ar = rr = aw = rw = 0
  reading_value = writing_value = 0
  mutex_value = 1

Process writer:
  repeat
    P(mutex);
    if rr > 0
      then begin
        aw := aw + 1;
        V(mutex);
        P(writing)
      end
    else begin
        rw := rw + 1;
        V(mutex);
        while (rr > 0) do skip
      end;
    critical section;
    P(mutex);
    rw := rw - 1;
    if aw > 0
      then begin
        aw := aw - 1;
        V(writing)
      end
    else
      while ar > 0 do begin
        ar := ar - 1;
        V(reading)
      end;
    V(mutex);
  until false;

Process granter:
  begin
    P(mutex);
    if aw = 0
      then begin
        rr := rr + 1;
        V(reading)
      end
    else
      ar := ar + 1;
    V(mutex);
    P(reading);
    other work
  end;

