The following solution to the single producer single consumer problem uses semaphores for synchronization:

#define BUFFSIZE 100
buffer buf[BUFFSIZE];
int first = last = 0;
semaphore b_full = 0;
semaphore b_empty = BUFFSIZE;

void producer() {
    while(1) {
        produce an item p;
        P(b_empty);
        buf[last] = p;
        last = (last+1) % BUFFSIZE;
        V(b_full);
    }
}

void consumer() {
    while(1) {
        P(b_full);
        c = buf[first];
        first = (first+1) % BUFFSIZE;
        V(b_empty);
        consume item c;
    }
}

